15: static constexpr uint64_t MaxSendmsgSize = 4096;
16: static constexpr absl::Duration CONNECTION_REFUSED_RETRY_DELAY = absl::Seconds(1);
17: static constexpr int SENDMSG_MAX_RETRIES = 10;
18: 
19: RpcStream::~RpcStream() {
20:   if (domain_socket_ != -1) {
21:     Api::OsSysCalls& os_sys_calls = Api::OsSysCallsSingleton::get();
22:     Api::SysCallIntResult result = os_sys_calls.close(domain_socket_);
23:     ASSERT(result.return_value_ == 0);
24:   }
25: }
26: 
27: void RpcStream::initDomainSocketAddress(sockaddr_un* address) {
28:   memset(address, 0, sizeof(*address));
29:   address->sun_family = AF_UNIX;
30: }
31: 
32: sockaddr_un RpcStream::createDomainSocketAddress(uint64_t id, const std::string& role,
33:                                                  const std::string& socket_path,
34:                                                  mode_t socket_mode) {
35:   // Right now we only allow a maximum of 3 concurrent envoy processes to be running. When the third
36:   // starts up it will kill the oldest parent.
37:   static constexpr uint64_t MaxConcurrentProcesses = 3;
38:   id = id % MaxConcurrentProcesses;
39:   sockaddr_un address;
40:   initDomainSocketAddress(&address);
41:   auto addr = THROW_OR_RETURN_VALUE(
42:       Network::Address::PipeInstance::create(
43:           fmt::format("{}_{}_{}", socket_path, role, base_id_ + id), socket_mode, nullptr),
44:       std::unique_ptr<Network::Address::PipeInstance>);
45:   safeMemcpy(&address, &(addr->getSockAddr()));
46:   fchmod(domain_socket_, socket_mode);
47: 
48:   return address;
49: }
50: 
51: void RpcStream::bindDomainSocket(uint64_t id, const std::string& role,
52:                                  const std::string& socket_path, mode_t socket_mode) {
53:   Api::OsSysCalls& os_sys_calls = Api::OsSysCallsSingleton::get();
54:   // This actually creates the socket and binds it. We use the socket in datagram mode so we can
55:   // easily read single messages.
56:   domain_socket_ = socket(AF_UNIX, SOCK_DGRAM | SOCK_NONBLOCK, 0);
57:   sockaddr_un address = createDomainSocketAddress(id, role, socket_path, socket_mode);
58:   unlink(address.sun_path);
59:   Api::SysCallIntResult result =
60:       os_sys_calls.bind(domain_socket_, reinterpret_cast<sockaddr*>(&address), sizeof(address));
61:   if (result.return_value_ != 0) {
62:     const auto msg = fmt::format(
63:         "unable to bind domain socket with base_id={}, id={}, errno={} (see --base-id option)",
64:         base_id_, id, result.errno_);
65:     if (result.errno_ == SOCKET_ERROR_ADDR_IN_USE) {
66:       throw HotRestartDomainSocketInUseException(msg);
67:     }
68:     throw EnvoyException(msg);
69:   }
70: }
71: 
72: bool RpcStream::sendHotRestartMessage(sockaddr_un& address, const HotRestartMessage& proto,
73:                                       bool allow_failure) {
74:   Api::OsSysCalls& os_sys_calls = Api::OsSysCallsSingleton::get();
75:   const uint64_t serialized_size = proto.ByteSizeLong();
76:   const uint64_t total_size = sizeof(uint64_t) + serialized_size;
77:   // Fill with uint64_t 'length' followed by the serialized HotRestartMessage.
78:   std::vector<uint8_t> send_buf;
79:   send_buf.resize(total_size);
80:   *reinterpret_cast<uint64_t*>(send_buf.data()) = htobe64(serialized_size);
81:   RELEASE_ASSERT(proto.SerializeWithCachedSizesToArray(send_buf.data() + sizeof(uint64_t)),
82:                  "failed to serialize a HotRestartMessage");
83: 
84:   RELEASE_ASSERT(fcntl(domain_socket_, F_SETFL, 0) != -1,
85:                  fmt::format("Set domain socket blocking failed, errno = {}", errno));
86: 
87:   uint8_t* next_byte_to_send = send_buf.data();
88:   uint64_t sent = 0;
89:   while (sent < total_size) {
90:     const uint64_t cur_chunk_size = std::min(MaxSendmsgSize, total_size - sent);
91:     iovec iov[1];
92:     iov[0].iov_base = next_byte_to_send;
93:     iov[0].iov_len = cur_chunk_size;
94:     next_byte_to_send += cur_chunk_size;
95:     sent += cur_chunk_size;
96:     msghdr message;
97:     memset(&message, 0, sizeof(message));
98:     message.msg_name = &address;
99:     message.msg_namelen = sizeof(address);
100:     message.msg_iov = iov;
101:     message.msg_iovlen = 1;
102: 
103:     // Control data stuff, only relevant for the fd passing done with PassListenSocketReply.
104:     uint8_t control_buffer[CMSG_SPACE(sizeof(int))];
105:     if (replyIsExpectedType(&proto, HotRestartMessage::Reply::kPassListenSocket) &&
106:         proto.reply().pass_listen_socket().fd() != -1) {
107:       memset(control_buffer, 0, CMSG_SPACE(sizeof(int)));
108:       message.msg_control = control_buffer;
109:       message.msg_controllen = CMSG_SPACE(sizeof(int));
110:       cmsghdr* control_message = CMSG_FIRSTHDR(&message);
111:       control_message->cmsg_level = SOL_SOCKET;
112:       control_message->cmsg_type = SCM_RIGHTS;
113:       control_message->cmsg_len = CMSG_LEN(sizeof(int));
114:       *reinterpret_cast<int*>(CMSG_DATA(control_message)) = proto.reply().pass_listen_socket().fd();
115:       ASSERT(sent == total_size, "an fd passing message was too long for one sendmsg().");
116:     }
117: 
118:     // A transient connection refused error probably means the old process is not ready.
119:     int saved_errno = 0;
120:     int rc = 0;
121:     bool sent = false;
122:     for (int i = 0; i < SENDMSG_MAX_RETRIES; i++) {
123:       auto result = os_sys_calls.sendmsg(domain_socket_, &message, 0);
124:       rc = result.return_value_;
125:       saved_errno = result.errno_;
126: 
127:       if (rc == static_cast<int>(cur_chunk_size)) {
128:         sent = true;
129:         break;
130:       }
131: 
132:       if (saved_errno == ECONNREFUSED) {
133:         if (allow_failure) {
134:           return false;
135:         }
136:         ENVOY_LOG(error, "hot restart sendmsg() connection refused, retrying");
137:         absl::SleepFor(CONNECTION_REFUSED_RETRY_DELAY);
138:         continue;
139:       }
140: 
141:       RELEASE_ASSERT(false, fmt::format("hot restart sendmsg() failed: returned {}, errno {}", rc,
142:                                         saved_errno));
143:     }
144: 
145:     if (!sent) {
146:       RELEASE_ASSERT(false, fmt::format("hot restart sendmsg() failed: returned {}, errno {}", rc,
147:                                         saved_errno));
148:     }
149:   }
