20: absl::optional<HotRestartingChild::UdpForwardingContext::ForwardEntry>
21: HotRestartingChild::UdpForwardingContext::getListenerForDestination(
22:     const Network::Address::Instance& address) {
23:   auto it = listener_map_.find(address.asString());
24:   if (it == listener_map_.end()) {
25:     // If no listener on the specific address was found, check for a default route.
26:     // If the address is IPv6, check default route IPv6 only, otherwise check default
27:     // route IPv4 then default route IPv6, as either can potentially receive an IPv4
28:     // packet.
29:     uint32_t port = address.ip()->port();
30:     if (address.ip()->version() == Network::Address::IpVersion::v6) {
31:       it = listener_map_.find(absl::StrCat("[::]:", port));
32:     } else {
33:       it = listener_map_.find(absl::StrCat("0.0.0.0:", port));
34:       if (it == listener_map_.end()) {
35:         it = listener_map_.find(absl::StrCat("[::]:", port));
36:         if (it != listener_map_.end() && it->second.first->ip()->ipv6()->v6only()) {
37:           // If there is a default IPv6 route but it's set v6only, don't use it.
38:           it = listener_map_.end();
39:         }
40:       }
41:     }
42:   }
43:   if (it == listener_map_.end()) {
44:     return absl::nullopt;
45:   }
46:   return it->second;
47: }
