61:   if (restart_epoch_ != 0) {
62:     parent_address_ = main_rpc_stream_.createDomainSocketAddress(restart_epoch_ + -1, "parent",
63:                                                                  socket_path, socket_mode);
64:     parent_address_udp_forwarding_ = udp_forwarding_rpc_stream_.createDomainSocketAddress(
65:         restart_epoch_ + -1, "parent", socket_path_udp, socket_mode);
66:   }
67:   main_rpc_stream_.bindDomainSocket(restart_epoch_, "child", socket_path, socket_mode);
