72: bool HotRestartingChild::abortDueToFailedParentConnection() {
73:   if (!skip_hot_restart_on_no_parent_) {
74:     return false;
75:   }
76:   HotRestartMessage wrapped_request;
77:   wrapped_request.mutable_request()->mutable_test_connection();
78:   if (!main_rpc_stream_.sendHotRestartMessage(parent_address_, wrapped_request, true)) {
79:     return true;
80:   }
81:   return false;
82: }
