139: HotRestartingParent::Internal::getListenSocketsForChild(const HotRestartMessage::Request& request) {
140:   HotRestartMessage wrapped_reply;
141:   wrapped_reply.mutable_reply()->mutable_pass_listen_socket()->set_fd(-1);
142:   Network::Address::InstanceConstSharedPtr addr =
143:       THROW_OR_RETURN_VALUE(Network::Utility::resolveUrl(request.pass_listen_socket().address()),
144:                             Network::Address::InstanceConstSharedPtr);
145: 
146:   for (const auto& listener : server_->listenerManager().listeners()) {
147:     for (auto& socket_factory : listener.get().listenSocketFactories()) {
148:       if (*socket_factory->localAddress() == *addr && listener.get().bindToPort()) {
149:         StatusOr<Network::Socket::Type> socket_type =
150:             Network::Utility::socketTypeFromUrl(request.pass_listen_socket().address());
151:         // socketTypeFromUrl should return a valid value since resolveUrl returned a valid address.
152:         ASSERT(socket_type.ok());
153: 
154:         if (socket_factory->socketType() == *socket_type) {
155:           // worker_index() will default to 0 if not set which is the behavior before this field
156:           // was added. Thus, this should be safe for both roll forward and roll back.
157:           if (request.pass_listen_socket().worker_index() < server_->options().concurrency()) {
158:             wrapped_reply.mutable_reply()->mutable_pass_listen_socket()->set_fd(
159:                 socket_factory->getListenSocket(request.pass_listen_socket().worker_index())
160:                     ->ioHandle()
161:                     .fdDoNotUse());
162:           }
163:           break;
164:         }
165:       }
166:     }
167:   }
168:   return wrapped_reply;
169: }
