175: void HotRestartingParent::Internal::exportStatsToChild(HotRestartMessage::Reply::Stats* stats) {
176:   server_->stats().forEachSinkedGauge(nullptr, [this, stats](Stats::Gauge& gauge) mutable {
177:     if (gauge.used()) {
178:       const std::string name = gauge.name();
179:       (*stats->mutable_gauges())[name] = gauge.value();
180:       recordDynamics(stats, name, gauge.statName());
181:     }
182:   });
183: 
184:   server_->stats().forEachSinkedCounter(nullptr, [this, stats](Stats::Counter& counter) mutable {
185:     if (counter.used()) {
186:       // The hot restart parent is expected to have stopped its normal stat exporting (and so
187:       // latching) by the time it begins exporting to the hot restart child.
188:       uint64_t latched_value = counter.latch();
189:       if (latched_value > 0) {
190:         const std::string name = counter.name();
191:         (*stats->mutable_counter_deltas())[name] = latched_value;
192:         recordDynamics(stats, name, counter.statName());
193:       }
194:     }
195:   });
196:   stats->set_memory_allocated(Memory::Stats::totalCurrentlyAllocated());
197:   stats->set_num_connections(server_->listenerManager().numConnections());
198: }
